function UILicense:calculateLevelInterval(level)
    local Interval = 0
    if level == 1 then
        Interval = "1"
    elseif 2 <= level and level <= 5 then
        Interval = "2_5"
    elseif 6 <= level and level <= 10 then
        Interval = "6_10"
    elseif 11 <= level and level <= 20 then
        Interval = "11_20"
    elseif 21 <= level and level <= 25 then
        Interval = "21_25"
    elseif 26 <= level and level <= 30 then
        Interval = "26_30"
    elseif 31 <= level and level <= 45 then
        Interval = "31_45"
    elseif 46 <= level and level <= 60 then
        Interval = "46_60"
    elseif 61 <= level and level <= 70 then
        Interval = "61_70"
    elseif 71 <= level and level <= 80 then
        Interval = "71_80"
    elseif 81 <= level then
        Interval = "80_120"
    end

    return Interval

end

function UILicense:checkHasLicense()
    if self.seasonDate > 0 then
        return true
    end
    CustomDialog.builder().setTitleText(Lang:getString("gui_bed_war_season_tip_title"))
                .setHideLeftButton()
                .setContentText(Lang:getString("gui_bed_war_season_tip_content"))
                .setRightText(Lang:getString("gui_dialog_tip_btn_sure"))
                .show()
    return false
end

