function UILicense:register()
    self:registerDataCallBack("BedWarLicenseData", function(data)
        self:onDataUpdate(data)
    end, JsonBuilderProcessor)

    self:registerDataCallBack("BedWarLicenseGetRewardSuccess", function(data)
        self:onGetRewardSuccess(data)
    end, JsonBuilderProcessor)

    self:registerDataCallBack("BedWarLicensePaySuccess", function(data)
        self:onPaySuccess(data)
    end, JsonBuilderProcessor)

    self:registerDataCallBack("BedWarLicenseExchangeSuccess", function(data)
        self:onExchangeSuccess(data)
    end, JsonBuilderProcessor)

    self:registerDataCallBack("LicenseDailyTask", function(data)
        self:onGetDailyTaskInfo(data)
    end, DataBuilderProcessor)

    self:registerDataCallBack("CleanTasks", function(data)
        self.taskList = {}
    end)

    self:registerDataCallBack("LicenseSeasonTask", function(data)
        self:onGetSeasonTaskInfo(data)
    end, DataBuilderProcessor)

    self:registerDataCallBack("LicenseFinishTask", function(data)
        self:onFinishTask(data)
    end, DataBuilderProcessor)

    self:registerDataCallBack("LicenseCleanTask", function(data)
        local type = data:getParam("Type")

        if type == "week" then
            self.taskList = {}
        elseif type == "season" then
            self.seasonTaskList = {}
        end
    end, DataBuilderProcessor)

    self:registerDataCallBack("LicenseWeekEXP", function(data)
        self.weekEXP = data:getNumberParam("WeekEXP")

        local weekConfig = LicenseConfig:getWeekConfig(self.seasonDate, self.week)
        if weekConfig then
            self.stTaskEXPLimit:SetText(self.weekEXP .. " / " .. weekConfig.EXPLimit)
        end
    end, DataBuilderProcessor)

    self:registerDataCallBack("HornNum", function(horns)
        self.hasHorn = tonumber(horns)
        PlayerWallet:setMoneyCount(Define.Money.HORN, tonumber(horns))
    end)

    self:registerDataCallBack("BuyCustomGoodsSuccess", function(goodsId)
        self:checkExchangeDressStatus(goodsId)
    end)

    self:registerDataCallBack("WatchLicenseADSuccess", function(data)
        self:onWatchLicenseADSuccess(data)
    end, DataBuilderProcessor)
end

function UILicense:onWatchLicenseADSuccess(data)
    self.curEXP = data:getNumberParam("curEXP")
    self.playerLevel = data:getNumberParam("curLV")
    self.freeUpgradeTime = data:getNumberParam("freeTime")

    self:showContent()
end

function UILicense:onFinishTask(data)
    self.curEXP = data:getNumberParam("EXP")
    self.playerLevel = data:getNumberParam("level")
    self.weekEXP = data:getNumberParam("weekLimit")

    local weekConfig = LicenseConfig:getWeekConfig(self.seasonDate, self.week)
    if not weekConfig then
        return
    end
    self.stTaskEXPLimit:SetText(self.weekEXP .. " / " .. weekConfig.EXPLimit)
    if self.playerLevel == #self.Rewards then
        self.curEXP = -1
    end

    if self.seasonDate ~= -1 and self.loadFinish then
        self:showContent()
    end
end

function UILicense:onGetDailyTaskInfo(data)
    local finishNum = data:getNumberParam("finishNum")
    local taskId = data:getNumberParam("taskId")
    local progress = data:getNumberParam("progress")
    local status = data:getNumberParam("status")

    local taskInfo = { taskId = taskId, progress = progress, status = status, finishNum = finishNum }
    local haveTask = false
    for index, task in pairs(self.taskList) do
        if task.taskId == taskId then
            table.remove(self.taskList, index)
            table.insert(self.taskList, index, taskInfo)
            haveTask = true
        end
    end
    if not haveTask then
        table.insert(self.taskList, taskInfo)
        self:onTaskListUpDate()
    else
        local item = self.lvTaskList:getItem("taskId", taskId)
        if item then
            item:onDataChange(taskInfo)
        end
    end
end

function UILicense:onGetSeasonTaskInfo(data)
    local refreshId = data:getNumberParam("refreshId")
    local taskId = data:getNumberParam("taskId")
    local progress = data:getNumberParam("progress")
    local status = data:getNumberParam("status")
    local taskInfo = { taskId = taskId, progress = progress, status = status }

    if refreshId == -1 then
        local haveTask = false
        for index, task in pairs(self.seasonTaskList) do
            if task.taskId == taskId then
                table.remove(self.seasonTaskList, index)
                table.insert(self.seasonTaskList, index, taskInfo)
                haveTask = true
            end
        end
        if not haveTask then
            table.insert(self.seasonTaskList, taskInfo)
        end
    else
        for index, task in pairs(self.seasonTaskList) do
            if task.taskId == refreshId then
                table.remove(self.seasonTaskList, index)
                table.insert(self.seasonTaskList, index, taskInfo)
            end
        end
    end
    table.sort(self.seasonTaskList, function(a, b)
        return a.taskId < b.taskId
    end)
    GUILicenseSeasonTask:updateData()
    GUILicenseSeasonTask:showRedPoint()
end

function UILicense:onGetRewardSuccess(data)
    self.bigRewardList = {}
    self.smallRewardList = {}
    self.getFreeReward = self.getFreeReward or {}
    self.getPayReward = self.getPayReward or {}
    for _, reward in pairs(data) do
        local rewardConfig = LicenseConfig:getRewardByLV(reward.Lv)
        if rewardConfig then
            self.smallRewardList[reward.rewardId] = self.smallRewardList[reward.rewardId] or 0
            if reward.rewardType == "free" then
                local rewardData = { rewardId = reward.rewardId, Lv = reward.Lv }
                table.insert(self.getFreeReward, rewardData)
                if rewardConfig.FreeSpecialReward == 1 then
                    table.insert(self.bigRewardList, reward.rewardId)
                else
                    self.smallRewardList[reward.rewardId] = self.smallRewardList[reward.rewardId] + rewardConfig.FreeNum
                end
            elseif reward.rewardType == "pay" then
                local rewardData = { rewardId = reward.rewardId, Lv = reward.Lv }
                table.insert(self.getPayReward, rewardData)
                if rewardConfig.PaySpecialReward == 1 then
                    table.insert(self.bigRewardList, reward.rewardId)
                else
                    self.smallRewardList[reward.rewardId] = self.smallRewardList[reward.rewardId] + rewardConfig.PayNum
                end
            end
        end
    end

    self:showRewardTip()
    self:itemStatusChange()
    self.rewardListAdapt:notifyDataChange()
end

function UILicense:showRewardTip()
    self.bigRewardList = self.bigRewardList or {}
    self.smallRewardList = self.smallRewardList or {}
    if #self.bigRewardList > 0 then
        local reward = { name = "", image = "" }
        local rewardId = table.remove(self.bigRewardList, 1)
        local rewardConfig = RewardConfig.findRewardById(rewardId)
        if rewardConfig then
            reward.image = rewardConfig.Image
            reward.name = rewardConfig.Name
        else
            local good = CustomShopConfig:getGoodsConfig(rewardId)
            if good then
                reward.image = good.Image
                reward.name = good.Name
            end
        end
        GUIChallengeRewardReceive:init(reward, false, function()
            LuaTimer:schedule(function()
                self:showRewardTip()
            end, 0)
        end)
        GUIChallengeRewardReceive.stRibbon:SetText(Lang:getString("bed.war.reward.title"))
        return
    end
    local result = {}
    for rewardId, count in pairs(self.smallRewardList) do
        if #result == 5 then
            break
        end
        if count ~= 0 then
            local rewardConfig = RewardConfig.findRewardById(rewardId)
            if rewardConfig then
                table.insert(result, { Image = rewardConfig.Image, Name = rewardConfig.Name, Count = count })
                self.smallRewardList[rewardId] = nil
            else
                local good = CustomShopConfig:getGoodsConfig(rewardId)
                if good then
                    table.insert(result, { Image = good.Image, Name = good.Name, Count = count })
                    self.smallRewardList[rewardId] = nil
                end
            end
        end
    end
    if #result > 0 then
        GUIRewardResult:onShowRewardsTip(result, true, function()
            LuaTimer:schedule(function()
                self:showRewardTip()
            end, 0)
        end)
    end
end

function UILicense:updateRewardData(data)
    local rewards = {}
    for _, reward in pairs(data) do
        local rewardConfig = LicenseConfig:getRewardByLV(reward.Lv)
        if rewardConfig then
            local haveReward = false
            for _, rewardsItem in pairs(rewards) do
                if reward.rewardId == rewardsItem.rewardId then
                    haveReward = rewardsItem
                    break
                end
            end
            if haveReward then
                if reward.rewardType == "pay" then
                    haveReward.Num = haveReward.Num + rewardConfig.PayNum
                elseif reward.rewardType == "free" then
                    haveReward.Num = haveReward.Num + rewardConfig.FreeNum
                end
            else
                local temp = {}
                if reward.rewardType == "pay" then
                    temp = { rewardId = reward.rewardId, Num = rewardConfig.PayNum }
                elseif reward.rewardType == "free" then
                    temp = { rewardId = reward.rewardId, Num = rewardConfig.FreeNum }
                end
                table.insert(rewards, temp)
            end
            --else
            --    local temp = { rewardId = reward.rewardId, Num = rewardConfig.PayNum }
            --    table.insert(rewards, temp)
        end
    end
    return rewards
end

function UILicense:onPaySuccess(data)
    GUILicenseBuyLevelTip:hide()
    self.curEXP = data.curEXP
    self.playerLevel = data.curLV
    self.hadBuy = data.hadBuy

    if self.playerLevel == #self.Rewards then
        self.curEXP = -1
    end

    self:checkShowBigPriceByLevel()
    self:showContent()

    if self.hadBuy ~= 0 then
        self.btnBuy:SetText(Lang:getString("gui_bed_war_license_display"))
    else
        self.btnBuy:SetText(Lang:getString("gui_bed_war_license_buy"))
    end
end

function UILicense:onExchangeSuccess(data)
    local exchangeConfig = LicenseConfig:getExchangeConfigByItemId(self.seasonDate, data.itemId)
    if not exchangeConfig then
        return
    end

    local canFind = false
    for _, exchangeData in pairs(self.exchangeReward) do
        if exchangeData.itemId == data.itemId then
            canFind = true
            exchangeData.num = exchangeData.num + data.num
            break
        end
    end
    if not canFind then
        table.insert(self.exchangeReward, data)
    end
    ---如果兑换的是宝箱则 自动开启
    local rewardConfig = RewardConfig.findRewardById(data.itemId)
    if rewardConfig and tonumber(rewardConfig.RewardType) == Define.RewardType.CHEST then
        --for _ = 1, exchangeConfig.Num * data.num * rewardConfig.Count do
        --    OpenLotteryBoxEvent:invoke(tonumber(rewardConfig.RewardId))
        --end
    else
        if rewardConfig and tonumber(rewardConfig.RewardType) == Define.RewardType.CUSTOM_SHOP then
            table.insert(self.dress, data.itemId)
        end
        self.smallRewardList = {}
        self.smallRewardList[data.itemId] = exchangeConfig.Num * data.num
        self:showRewardTip()
    end
    self:ExchangeListUpDate()
end

function UILicense:onDataUpdate(data)
    self.playerLevel = data.license_level or 1
    self.hadBuy = data.license_buy or 0
    self.weekEXP = data.license_week_exp or 0
    self.curEXP = data.license_exp or 0
    self.hasHorn = data.had_horn or 0
    self.freeUpgradeTime = data.free_upgrade_time or DateUtil.getYearDay()
    self.getFreeReward = data.get_free_reward or {}
    self.getPayReward = data.get_pay_reward or {}
    self.exchangeReward = data.exchange_reward or {}
    self.dress = data.had_get_dress or {}
    --self.customGood = data.had_get_custom or {}
    self.week = data.license_week or 1
    self.showEffectTask = data.show_effect_task or {}
    if self.playerLevel == #self.Rewards then
        self.curEXP = -1
    end
    if self.seasonDate ~= data.season_data and self.seasonDate ~= nil then
        self.seasonDate = data.season_data
        if self.seasonDate > 0 then
            self.Rewards = TableUtil.copyTable(LicenseConfig:getLevelRewardBySeason(self.seasonDate))
            self.Exchange = TableUtil.copyTable(LicenseConfig:getExchangeConfigBySeason(self.seasonDate))
            self.endSeasonDate = LicenseConfig:getSeasonEndTime(self.seasonDate)
        else
            self.Rewards = { }
            self.Exchange = { }
            self.endSeasonDate = -1
        end
    end
    local weekConfig = LicenseConfig:getWeekConfig(self.seasonDate, self.week)
    if weekConfig then
        self.stTaskEXPLimit:SetText(self.weekEXP .. " / " .. weekConfig.EXPLimit)
    end
    self.exchangeSelect = -1
    self.loadFinish = true
    self:showContent()
    self:onTaskListUpDate()
    GUILicenseGrandPriceDisplay:setItemData(self.seasonDate)

    if self:isShow() then
        local seasonConfig = LicenseConfig:getSeasonConfigBySeason(self.seasonDate)
        if seasonConfig then
            self.siRewardDisplayActor:SetActor1(seasonConfig.PetActorName, seasonConfig.PetSkillName)
            local skillTime = self.siRewardDisplayActor:GetActor():GetSkillTimeLength(seasonConfig.PetSkillName)
            LuaTimer:cancel(self.rewardDisplaySkillKey)
            self.rewardDisplaySkillKey = LuaTimer:scheduleTimer(function()
                local curRotate = self.siRewardDisplayActor:GetRotateY()
                self.siRewardDisplayActor:SetActor1("", "", curRotate)
                self.siRewardDisplayActor:SetActor1(seasonConfig.PetActorName, seasonConfig.PetSkillName, curRotate)
            end, skillTime)
            self.btnBuy:SetText(Lang:getString("gui_bed_war_license_buy"))
            self:showDescribe("", "", 2)
            self.siRewardDisplayImage:SetVisible(true)
        end
    end

    if GUILicenseRewardBuy:isShow() then
        GUILicenseRewardBuy:onShow("seasonChange")
    end
end

function UILicense:showContent()
    self:itemStatusChange()
    self:RewardListUpDate()
    self:ExchangeListUpDate()
    self:onPlayerDataUpDate()
end

function UILicense:onPlayerDataUpDate()
    self.stRewardLevel:SetText("LV. " .. self.playerLevel)
    self.stExchangeLevel:SetText("LV. " .. self.playerLevel)
    self.stTaskLevel:SetText("LV. " .. self.playerLevel)
    GUILicenseSeasonTask.stLevel:SetText("LV. " .. self.playerLevel)
    if self.curEXP == -1 then
        self.pbRewardLevel:SetProgress(1)
        self.stRewardEXP:SetText("MAX")

        self.pbExchangeLevel:SetProgress(1)
        self.stExchangeEXP:SetText("MAX")

        self.pbTaskLevel:SetProgress(1)
        self.stTaskEXP:SetText("MAX")

        GUILicenseSeasonTask.pbLevelProgress:SetProgress(1)
        GUILicenseSeasonTask.stLevelProgress:SetText("MAX")

    elseif self.Rewards and self.Rewards[self.playerLevel] ~= nil then
        local expValue = self.curEXP / self.Rewards[self.playerLevel].NeedEXP
        local expText = self.curEXP .. "/" .. self.Rewards[self.playerLevel].NeedEXP
        self.pbRewardLevel:SetProgress(expValue)
        self.stRewardEXP:SetText(expText)

        self.pbExchangeLevel:SetProgress(expValue)
        self.stExchangeEXP:SetText(expText)

        self.pbTaskLevel:SetProgress(expValue)
        self.stTaskEXP:SetText(expText)

        GUILicenseSeasonTask.pbLevelProgress:SetProgress(expValue)
        GUILicenseSeasonTask.stLevelProgress:SetText(expText)
    end

    local seasonConfig = LicenseConfig:getSeasonConfigBySeason(self.seasonDate)
    local stTitle = self:getChildWindow("BedWarLicense-Season-Text", GUIType.StaticText)
    local stTitle2 = self:getChildWindow("BedWarLicense-Season-Text2", GUIType.StaticText)
    local stLicenseText1 = self:getChildWindow("BedWarLicense-License_Text1", GUIType.StaticText)
    local stLicenseText2 = self:getChildWindow("BedWarLicense-License_Text2", GUIType.StaticText)
    stTitle:SetText(Lang:getString("gui_bed_war_license_title"))
    stTitle2:SetText(Lang:getString("gui_bed_war_license_title"))
    local weekConfig = LicenseConfig:getWeekConfig(self.seasonDate, self.week)
    if seasonConfig then
        local width = stTitle:GetFont():GetTextExtent(Lang:getString("gui_bed_war_license_title") .. "/", 1)
        stTitle:SetWidth({ 0, width })
        stTitle2:SetWidth({ 0, width })
        stTitle:SetText(Lang:getString("gui_bed_war_license_title") .. "/")
        stTitle2:SetText(Lang:getString("gui_bed_war_license_title") .. "/")
        stLicenseText1:SetText(Lang:getString(seasonConfig.SeasonLang))
        stLicenseText2:SetText(Lang:getString(seasonConfig.SeasonLang))
        GUILicenseSeasonTask.stLicenseText1:SetText(Lang:getString(seasonConfig.SeasonLang))
        GUILicenseSeasonTask.stLicenseText2:SetText(Lang:getString(seasonConfig.SeasonLang))
    end
    if weekConfig then
        self.stTaskEXPLimit:SetText(self.weekEXP .. " / " .. weekConfig.EXPLimit)
    end

    if self.hadBuy ~= nil then
        if self.hadBuy > 0 then
            self.siLock:SetVisible(false)
        else
            self.siLock:SetVisible(true)
        end
    end
end

function UILicense:itemStatusChange()
    ---奖励状态 0--不可领取 1--可领取 2--已领取
    for _, reward in pairs(self.Rewards) do
        reward.FreeStatue = 0
        reward.PayStatue = 0
        if reward.Lv <= self.playerLevel then
            if reward.FreeReward ~= "#" then
                reward.FreeStatue = 1
            end
            if self.hadBuy ~= 0 then
                if reward.PayReward ~= "#" then
                    reward.PayStatue = 1
                end
            end
            for _, hadGetReward in pairs(self.getFreeReward) do
                if reward.FreeReward == hadGetReward.rewardId and reward.Lv == hadGetReward.Lv then
                    reward.FreeStatue = 2
                end
            end
            for _, hadGetReward in pairs(self.getPayReward) do
                if reward.PayReward == hadGetReward.rewardId and reward.Lv == hadGetReward.Lv and self.hadBuy ~= 0 then
                    reward.PayStatue = 2
                end
            end
        end
    end
    self:showRedPoint()
end

function UILicense:onShow(tabIndex)
    LuaTimer:cancel(self.rewardDisplaySkillKey)
    if BaseMain:getGameType() == "g1046" and Game:isEnableIndie() then
        GUIManager:addShowQueue(GUILicense, 1)
    end

    if self.seasonDate == -1 then
        self:hide()
        CustomDialog.builder()
                    .setHideLeftButton()
                    .setTitleText("gui_challenge_not_open_title")
                    .setContentText(Lang:getString("gui_challenge_not_open"))
                    .setRightText(Lang:getString("gui_dialog_tip_btn_sure"))
                    .show()
        return
    end

    tabIndex = tabIndex or 1
    self.siRewardDisplayImage:SetVisible(true)
    local seasonConfig = LicenseConfig:getSeasonConfigBySeason(self.seasonDate)
    if seasonConfig then
        self.siRewardDisplayActor:SetActor1(seasonConfig.PetActorName, seasonConfig.PetSkillName)
        local skillTime = self.siRewardDisplayActor:GetActor():GetSkillTimeLength(seasonConfig.PetSkillName)
        self.rewardDisplaySkillKey = LuaTimer:scheduleTimer(function()
            local curRotate = self.siRewardDisplayActor:GetRotateY()
            self.siRewardDisplayActor:SetActor1("", "", curRotate)
            self.siRewardDisplayActor:SetActor1(seasonConfig.PetActorName, seasonConfig.PetSkillName, curRotate)
        end, skillTime)
    end

    self.reFreshTime = DateUtil.getWeekLastTime(os.time(), true) + 22 * 3600
    self.refreshId = 0
    for _, layout in pairs(self.pages) do
        if layout:IsVisible() then
            layout:SetVisible(false)
        end
    end
    local Tabs = LicenseConfig.TabConfig
    if not Tabs then
        return
    end
    self.lvTabs:clearItems()
    local tabsWidth = self.lvTabs:getWidth()
    for index, data in pairs(Tabs) do
        local tab = GUILicenseTab.new("BedWarLicenseTab.json")
        tab:onDataChanged(data)
        tab:setHeight({ 1, 0 })
        tab:setWidth({ 0, (tabsWidth - 8) / 3 })
        self.lvTabs:addItem(tab)
        if index == tabIndex then
            self.curSelectId = 0
            self:onSelectChange(data.Id)
        end
    end

    if self.seasonDate ~= -1 then
        self:showContent()
        for i = self.playerLevel + 1, #self.Rewards do
            if self.Rewards[i].StageReward == 1 then
                if self.hadBuy ~= 0 then
                    self.siTaskDescribe:SetImage(self.Rewards[i].PayRewardImage)
                    self.stNextRewardName:SetText(Lang:getString(self.Rewards[i].PayDesc))
                else
                    self.siTaskDescribe:SetImage(self.Rewards[i].FreeRewardImage)
                    self.stNextRewardName:SetText(Lang:getString(self.Rewards[i].FreeDesc))
                end
                self.stNextRewardLevel:SetText(i)
                break
            end
        end
    end
    if self.hadBuy ~= 0 then
        self.btnBuy:SetText(Lang:getString("gui_bed_war_license_display"))
    else
        self:checkShowBigPriceByLevel()
        self.btnBuy:SetText(Lang:getString("gui_bed_war_license_buy"))
    end
    self.llMoney:SetVisible(true)
end

function UILicense:checkShowBigPriceByLevel()
    if self.hadBuy ~= 0 then
        return
    end
    local seasonConfig = LicenseConfig:getSeasonConfigBySeason(self.seasonDate)
    if not seasonConfig then
        return
    end
    local llGuide = GUIManager:getWindowByName("GuideSystem")
    for index, showLevel in pairs(seasonConfig.ShowBuyLevel) do
        if self.playerLevel == tonumber(showLevel) and not llGuide:IsVisible() and
                tonumber(ClientHelper.getStringForKey("showBigPriceLevel", 1)) ~= self.playerLevel then
            ClientHelper.putStringForKey("showBigPriceLevel", tostring(self.playerLevel))
            table.remove(seasonConfig.ShowBuyLevel, index)
            GUILicenseBigPrice:show()
        end
    end
end

function UILicense:onTaskListUpDate()
    self.lvTaskList:clearItems()
    for _, data in pairs(self.taskList) do
        local task = GUILicenseTaskItem.new("BedWarLicenseTaskItem.json")
        task:setWidth({ 1, 0 })
        task:onDataChange(data)
        self.lvTaskList:addItem(task)
    end
end

function UILicense:onTick()
    self.llDiamond:onTick()
    self.llHorn:onTick()
    if self.seasonDate ~= -1 then
        local time = os.time()
        local refreshTime = self.reFreshTime - time
        local RefreshTime = math.floor(refreshTime / 3600)
        local refreshDay = math.floor(RefreshTime / 24)
        local refreshHour = RefreshTime - refreshDay * 24
        if time < self.endSeasonDate and self.endSeasonDate ~= -1 then
            local lastTime = self.endSeasonDate - time
            local day = math.floor(lastTime / (24 * 3600))
            local hour = math.floor((lastTime - day * (24 * 3600)) / 3600)
            local lastString = string.format(Lang:getString("gui_bed_war_license_reward_time"), day, hour)
            self.stRewardTime:SetText(Lang:getString(lastString))
            self.stExchangeTime:SetText(Lang:getString(lastString))
        end
        local refreshText = string.format(Lang:getString("gui_bed_war_license_task_refresh_time"), refreshDay, refreshHour)
        self.stTaskRefreshTime:SetText(refreshText)local curOffset = self.gvRewardList.root:GetScrollOffset()
        if curOffset > 0 then
            local item = self.gvRewardList:getItem("Lv", 1)
            if item then
                item.siExtraLine:SetArea({ 0, -curOffset }, { 0.471649, 0 }, { 0, curOffset }, { 0.061856, 0 })
            end
            return
        end
        if -(curOffset - self.offset) > 10 * self.rewardItemWidth[2] then
            self.btnBack:SetVisible(true)
        else
            self.btnBack:SetVisible(false)
        end
        local grandPriceLevel = math.floor(-curOffset / self.rewardItemWidth[2] + 5.6)
        for i = grandPriceLevel, #self.Rewards do
            if self.Rewards[i].StageReward == 1 then
                if self.Rewards[i].FreeShowType == 2 then
                    self.siFreeRewardEffect:SetVisible(true)
                else
                    self.siFreeRewardEffect:SetVisible(false)
                end

                if self.Rewards[i].PayShowType == 2 then
                    self.siPayRewardEffect:SetVisible(true)
                else
                    self.siPayRewardEffect:SetVisible(false)
                end
                self.tvRightRewardUp:SetVisible(self.Rewards[i].FreeNum > 0)
                self.tvRightRewardDown:SetVisible(self.Rewards[i].PayNum > 0)
                self.siFreeStageReward:SetImage(self.Rewards[i].FreeRewardImage)
                self.siPayStageReward:SetImage(self.Rewards[i].PayRewardImage)
                self.siFreeStageRewardHadGet:SetVisible(self.Rewards[i].FreeStatue == 2)
                self.siPayStageRewardHadGet:SetVisible(self.Rewards[i].PayStatue == 2)
                self.stRewardLineLevel:SetText(i)
                self.stRewardRightUpNum:SetText("×" .. self.Rewards[i].FreeNum)
                self.stRewardRightDownNum:SetText("×" .. self.Rewards[i].PayNum)
                self.cueStageLevel = i
                break
            end
        end
    end
end

function UILicense:RewardListUpDate()
    ---状态 0-已领取 1-可领取 2-不可领取
    for index, reward in pairs(self.Rewards) do
        if reward.FreeReward ~= "#" then
            local freeReward = RewardConfig.findRewardById(reward.FreeReward)
            if freeReward then
                reward.FreeType = tonumber(freeReward.RewardType)
                reward.FreeRewardImage = freeReward.Image
                reward.FreeDesc = freeReward.Desc
                reward.freeRewardStatue = 0
            end
        else
            reward.FreeType = 0
            reward.FreeRewardImage = ""
            reward.FreeDesc = ""
            reward.freeRewardStatue = 0
        end
        if reward.PayReward ~= "#" then
            local payReward = RewardConfig.findRewardById(reward.PayReward)
            if payReward then
                reward.PayType = tonumber(payReward.RewardType)
                reward.PayRewardImage = payReward.Image
                reward.PayDesc = payReward.Desc
                reward.payRewardStatue = 0
            end
        else
            reward.PayType = 0
            reward.PayRewardImage = ""
            reward.PayDesc = ""
            reward.payRewardStatue = 0
        end
    end
    self.rewardItemWidth = self.rewardListAdapt:getItemWidth()
    self.rewardListAdapt:setData(self.Rewards)
    if self.playerLevel + 3 < #self.Rewards then
        self.offset = -(self.playerLevel - 2) * self.rewardItemWidth[2]
        self.rewardListAdapt:setScrollOffset(self.offset) --4552
    else
        self.offset = -(#self.Rewards - 6) * self.rewardItemWidth[2]
        self.rewardListAdapt:setScrollOffset(self.offset) --4552
    end
end

function UILicense:showRedPoint()
    for i, reward in pairs(self.Rewards) do
        if reward.FreeStatue == 1 or reward.PayStatue == 1 then
            self.siGetAllRedPoint:SetVisible(true)
            if Game:isEnableIndie() and GameType == "g1046" then
                GUIIndieMain.siLicenseRedPoint:SetVisible(true)
            else
                GUIMain.ivLicenseRedPoint:SetVisible(true)
            end
            if GUIMain.cbMenuList:GetChecked() then
                GUIMain.siRedPoint:SetVisible(true)
            end
            return true
        end
    end
    self.siGetAllRedPoint:SetVisible(false)
    if Game:isEnableIndie() and GameType == "g1046" then
        GUIIndieMain.siLicenseRedPoint:SetVisible(false)
    else
        GUIMain.ivLicenseRedPoint:SetVisible(false)
    end
    return false
end

function UILicense:ExchangeListUpDate()
    ---0-已拥有，1-未拥有
    for _, exchange in pairs(self.Exchange) do
        exchange.Statue = 1
        exchange.hadExchange = 0
        for _, dress in pairs(self.dress) do
            if dress == exchange.ItemId then
                exchange.Statue = 0
            end
        end
        for _, hadExchange in pairs(self.exchangeReward) do
            if hadExchange.itemId == exchange.ItemId then
                exchange.hadExchange = hadExchange.num
            end
        end
    end
    self.exchangeListAdapt:setData(self.Exchange)
    if self.exchangeSelect == -1 and #self.Exchange >= 1 then
        self:onExchangeItemChange(self.Exchange[1])
    end
end

function UILicense:checkExchangeDressStatus(itemId)
    local change = false
    for _, exchange in pairs(self.Exchange) do
        local itemConfig = RewardConfig.findRewardById(exchange.ItemId)
        if itemConfig then
            if itemConfig.RewardId == tonumber(itemId) then
                table.insert(self.dress, exchange.ItemId)
                change = true
            end
        end
    end
    if change then
        self:onExchangeItemChange(self.Exchange[1])
    end
end

function UILicense:onSelectChange(selectId)
    local items = self.lvTabs.items
    for _, item in pairs(items) do
        if item.tabId == self.curSelectId and self.curSelectId ~= 0 then
            item:setChecked(false)
            self.pages[item.tabId]:SetVisible(false)
        end
        if item.tabId == selectId then
            item:setChecked(true)
            self.pages[item.tabId]:SetVisible(true)
        end
    end
    self.curSelectId = selectId
end

function UILicense:onRewardSelectChange(selectId, position)
    self.rewardSelect.Index = selectId
    self.rewardSelect.position = position

    self.rewardListAdapt:notifyDataChange()
end

function UILicense:showDescribe(image, describe, showType, actor, skillName)
    LuaTimer:cancel(self.actorSkillKey or 0)
    self.siRewardDisplayImage:SetVisible(false)
    if showType == 3 then
        self.awRewardActor:SetActor1("", "", 0)
        self.awRewardActor:SetActor1(actor, skillName, 0)
        self.siRewardDescribe:SetVisible(false)
        self.awRewardActor:SetVisible(true)
        self.siRewardDescribeEffect:SetVisible(false)
        local skillTime = self.awRewardActor:GetActor():GetSkillTimeLength(skillName)
        self.actorSkillKey = LuaTimer:scheduleTimer(function()
            local curRotate = self.awRewardActor:GetRotateY()
            self.awRewardActor:SetActor1("", "", curRotate)
            self.awRewardActor:SetActor1(actor, skillName, curRotate)
        end, skillTime)
    else
        if showType == 2 then
            self.siRewardDescribeEffect:SetVisible(true)
        else
            self.siRewardDescribeEffect:SetVisible(false)
        end

        self.siRewardDescribe:SetImage(image)
        self.siRewardDescribe:SetVisible(true)
        self.awRewardActor:SetVisible(false)
    end
    self.stRewardDescribe:SetText(Lang:getString(describe))
end

function UILicense:onExchangeItemChange(exchangeData)
    GUILicenseExchangeNum.price = exchangeData.Price
    self.canExchange = exchangeData.BuyLimit - exchangeData.hadExchange
    self.siExchangeDescribe:SetImage(exchangeData.Image)
    self.stExchangeDescribe:SetText(Lang:getString(exchangeData.Desc))
    if exchangeData.LVLimit > self.playerLevel then
        self.btnCannotExchange:SetVisible(false)
        self.btnExchange:SetVisible(true)
        self.btnExchange:SetNormalImage("set:bedwar_licenseexchange.json image:cannot_exchange")
        self.stExchangePrice:SetText(exchangeData.Price)
        self.btnExchange:SetTouchable(false)
        self.btnExchangeOne:SetVisible(false)
        self.btnExchangeTen:SetVisible(false)
    elseif exchangeData.Statue == 0 then
        self.btnCannotExchange:SetVisible(true)
        self.btnExchange:SetVisible(false)
    else
        self.stExchangePrice:SetText(exchangeData.Price)
        self.btnCannotExchange:SetVisible(false)
        self.btnExchange:SetNormalImage("set:bedwar_license.json image:btn_yello")
        self.btnExchange:SetTouchable(true)
        self.btnExchange:SetVisible(true)
        self.btnExchangeOne:SetVisible(true)
        self.stExchangeOnePrice:SetText(exchangeData.Price)
        self.btnExchangeTen:SetVisible(true)
        self.stExchangeTenPrice:SetText(exchangeData.Price * 10)
    end
    local rewardConfig = RewardConfig.findRewardById(exchangeData.ItemId)
    if rewardConfig and tonumber(rewardConfig.RewardType) == Define.RewardType.CHEST then
        self.btnExchangeDetail:SetVisible(true)
        self.ExchangeDetail = rewardConfig.RewardId
        self.llExchangeOne:SetVisible(false)
        self.llExchangeTen:SetVisible(true)
    else
        self.btnExchangeDetail:SetVisible(false)
        self.llExchangeOne:SetVisible(true)
        self.llExchangeTen:SetVisible(false)
    end
    if exchangeData.ItemId == self.exchangeSelect then
        return
    end
    self.exchangeSelect = exchangeData.ItemId
    self.exchangeListAdapt:notifyDataChange()
end


function UILicense:isSelect(selectId, position)
    if self.rewardSelect.Index == selectId and self.rewardSelect.position == position then
        return true
    end
    return false
end

function UILicense:isShowEXP(Lv)
    if Lv <= self.playerLevel then
        return true
    end
    return false
end

function UILicense:isShowBuyLevel(Lv)
    ---买等级按钮是当前等级的下一个等级的Item来显示
    if Lv == self.playerLevel + 1 then
        return true
    end
    return false
end

function UILicense:isExchangeSelect(selectId)
    if self.exchangeSelect == selectId then
        return true
    end
    return false
end

function UILicense:canExchangeNumByMoney()
    local price
    for _, reward in pairs(self.Exchange) do
        if reward.ItemId == self.exchangeSelect then
            price = reward.Price
        end
    end
    return self.hasHorn / price
end

function UILicense:onExchange(num)
    if self.seasonDate ~= -1 then
        if self.canExchange < num then
            GUILicenseTip:show("cannot_exchange")
        else
            if self.hasHorn >= tonumber(self.stExchangePrice:GetText()) * num then
                GamePacketSender:sendBedWarLicenseExchange(GUILicense.seasonDate, GUILicense.exchangeSelect, num)
            else
                GUIStore:show(StoreId.CubeStore, 10)
            end
        end
    end
end

return UILicense